SELECT id, user_id, username, login_time, logout_time, client_ip, user_agent, result_status, fail_reason
FROM sys_login_log


        AND username ILIKE '%' || #{username} || '%'


        AND result_status = #{resultStatus}

    AND login_time >= #{startTime}
    AND login_time <= #{endTime}

        AND (username ILIKE '%' || #{keyword} || '%' OR client_ip ILIKE '%' || #{keyword} || '%')


ORDER BY login_time DESC
LIMIT #{size} OFFSET #{offset}

SELECT count(*) FROM sys_login_log


        AND username ILIKE '%' || #{username} || '%'


        AND result_status = #{resultStatus}

    AND login_time >= #{startTime}
    AND login_time <= #{endTime}

        AND (username ILIKE '%' || #{keyword} || '%' OR client_ip ILIKE '%' || #{keyword} || '%')

SELECT id, user_id, username, login_time, logout_time, client_ip, user_agent, result_status, fail_reason
FROM sys_login_log
WHERE user_id = #{userId}
ORDER BY login_time DESC
LIMIT #{size} OFFSET #{offset}
